+
+        let rl = DatadogError::RateLimited {
+            retry_after_ms: 1000,
+        };
+        assert_eq!(rl.to_string(), "Rate limited, retry after 1000ms");
+
+        let api = DatadogError::Api {
+            status_code: 500,
+            message: "Internal".into(),
+        };
+        assert_eq!(api.to_string(), "Datadog API error (500): Internal");
+    }
+}

