+//! Integration tests for the FCP Datadog connector.
+
+use std::sync::Arc;
+use std::sync::atomic::Ordering;
+
+use fcp_datadog::client::{DatadogAuth, DatadogClient};
+use fcp_datadog::connector::DatadogConnector;
+use fcp_datadog::error::DatadogError;
+use serde_json::json;
+use wiremock::matchers::{header, method, path, path_regex};
+use wiremock::{Mock, MockServer, ResponseTemplate};
+
+// -- Helper --
+
+async fn configured_connector(mock_url: &str) -> DatadogConnector {
+    let mut connector = DatadogConnector::new();
+    let params = json!({
+        "api_key": "test-api-key",
+        "app_key": "test-app-key",
+        "base_url": mock_url,
+    });
+    connector.handle_configure(params).await.unwrap();
+    connector
+        .handle_handshake(json!({"session_id": "test-session"}))
+        .await
+        .unwrap();
+    connector
+}
+
+fn test_client(mock_url: &str) -> DatadogClient {
+    let client = reqwest::Client::new();
+    DatadogClient::with_client(
+        client,
+        DatadogAuth::ApiKeys {
+            api_key: "test-api".into(),
+            app_key: "test-app".into(),
+        },
+        mock_url,
+    )
+}
+
+// -- Lifecycle tests --
+
+#[tokio::test]
+async fn configure_with_api_keys() {
+    let mut connector = DatadogConnector::new();
+    let result = connector
+        .handle_configure(json!({
+            "api_key": "my-api-key",
+            "app_key": "my-app-key"
+        }))
+        .await;
+    assert!(result.is_ok());
+}
+
+#[tokio::test]
+async fn configure_missing_app_key_fails() {
+    let mut connector = DatadogConnector::new();
+    let result = connector
+        .handle_configure(json!({"api_key": "my-api-key"}))
+        .await;
+    assert!(result.is_err());
+}
+
+#[tokio::test]
